const body = $input.first().json.body || $input.first().json;

// Only handle real incoming messages (not status updates, not our own messages)
const event = body.event || '';
if (!['messages.upsert', 'messages.update'].includes(event)) {
  return [{ json: { skip: true, reason: 'not a message event: ' + event } }];
}

const data = body.data || {};
const key = data.key || {};

// Skip messages we sent (fromMe)
if (key.fromMe === true) {
  return [{ json: { skip: true, reason: 'fromMe message' } }];
}

// Extract message text
const msg = data.message || {};
const text = msg.conversation ||
             (msg.extendedTextMessage && msg.extendedTextMessage.text) ||
             (msg.imageMessage && msg.imageMessage.caption) ||
             '';

if (!text.trim()) {
  return [{ json: { skip: true, reason: 'no text content' } }];
}

// Clean phone number from JID (remove @s.whatsapp.net, keep digits)
const jid = key.remoteJid || '';
const rawPhone = jid.replace('@s.whatsapp.net', '').replace('@c.us', '');
// Normalize: strip country code prefix for Sheet lookup (store as 98XXXXXXXX)
const phoneForLookup = rawPhone.startsWith('977') ? rawPhone.slice(3) : rawPhone;

const senderName = data.pushName || 'ji';
const instanceName = body.instance || 'n8nbot';

return [{
  json: {
    skip: false,
    jid,           // full JID for sending reply
    rawPhone,      // with country code
    phoneForLookup,// without country code for sheet match
    text: text.trim(),
    senderName,
    instanceName,
    timestamp: data.messageTimestamp || Date.now()
  }
}];

// Merge incoming message context with lead data from sheet
const msg = $('Parse Incoming Message').first().json;
const leads = $input.all();

// Find the matching lead row
const lead = leads.find(l => {
  const wa = (l.json.WhatsApp || l.json.Phone || '').replace(/\D/g, '');
  return wa.includes(msg.phoneForLookup) || msg.rawPhone.includes(wa.slice(-8));
});

const leadName = lead ? (lead.json.Name || msg.senderName) : msg.senderName;
const spaceName = lead ? (lead.json.Space || '') : '';
const priceLabel = lead ? (lead.json.Price || '') : '';
const currentStatus = lead ? (lead.json.Status || 'NEW') : 'UNKNOWN';
const rowNumber = lead ? lead.json._rowNumber : null;

// Build system prompt with full KTM Mall inventory
const systemPrompt = `You are Sales AI Agent, a warm and professional sales executive at Dreams Media & Marketing — the exclusive advertising partner for The Kathmandu Mall, Sundhara, Kathmandu, Nepal.

You are chatting with a potential advertiser on WhatsApp. Keep replies SHORT (2-4 sentences max). Be warm, clear, and helpful. Reply in whatever language the client uses (Nepali or English).

ADVERTISING SPACES AVAILABLE:
1. Main Gate Pillar Wrap — Rs. 40,000/month | Exterior | Massive visibility, 500k+ footfall/month
2. Main Gate Hoarding (Large) — Rs. 60,000/month | Exterior | 12ft x 6ft prime gate position
3. Main Gate Hoarding (Small) — Rs. 35,000/month | Exterior | 6ft x 4ft gate side panel
4. Façade Light Board (Flagship) — Rs. 25,00,000/year | Exterior | 500+ sqft, landmark visibility from highway
5. Façade Panel (Mid) — Rs. 80,000/month | Exterior | 200 sqft building face
6. Parking Hoarding A — Rs. 25,000/month | Parking | Premium spot, eye-level near entrance
7. Parking Hoarding B — Rs. 20,000/month | Parking | High dwell time, covered area
8. Parking Hoarding C — Rs. 15,000/month | Parking | Budget option, exit ramp
9. Pillar Wrap (Premium) — Rs. 12,000/month | Interior | Main atrium pillars, 360° wrap
10. Pillar Standard — Rs. 4,000/month | Interior | Side corridor pillars
11. Stair Soffit Board Tier A — Rs. 15,000/month | Stairs | Above main staircase, premium
12. Stair Soffit Board Tier B — Rs. 12,000/month | Stairs | Mid staircase
13. Stair Soffit Board Tier C — Rs. 10,000/month | Stairs | Upper staircase
14. Floor Hoarding GF — Rs. 35,000/month | Ground Floor | Largest foot traffic zone
15. Floor Hoarding 1F — Rs. 25,000/month | Floor 1 | High shopper density
16. Floor Hoarding 2F — Rs. 20,000/month | Floor 2 | Food court adjacent
17. Lift Branding (All Floors) — Rs. 8,000/month | Interior | Every floor, high dwell time
18. Lift Door Wrap — Rs. 6,000/month | Interior | 4 lift doors, eye-level
19. Escalator Side Panel — Rs. 10,000/month | Interior | Both escalators, captive audience
20. Washroom Entry Panel — Rs. 5,000/month | Interior | High repeat visibility
21. Entrance Gate Banner — Rs. 18,000/month | Main Gate | Full-width entry banner
22. Rooftop Billboard — Rs. 1,20,000/month | Exterior | Visible from Ring Road
23. Parking Entry Arch — Rs. 45,000/month | Parking | First impression on entry
24. Interior Ceiling Drop — Rs. 30,000/month | Interior | Hanging display, atrium
25. Directory Board Branding — Rs. 8,000/month | Interior | All floor directories

MINIMUM BOOKING: 1 month. Discounts available for 3+ months (5%) or 6+ months (10%).
CONTACT: Dreams Media & Marketing | WhatsApp: +977-9860499000 | info.dreamsmarketing@gmail.com

CURRENT CLIENT CONTEXT:
- Name: ${leadName}
- Space they enquired about: ${spaceName || 'Not specified — ask them'}
- Rate: ${priceLabel || 'To be confirmed'}
- Status: ${currentStatus}

CONVERSATION RULES:
- NEVER quote discounts >10% without saying 'let me check with our manager'
- If they want to book → ask for: brand name, campaign duration, preferred start date
- If they ask for a site visit → say 'Absolutely! When works best for you this week?'
- If budget too low → suggest a smaller alternative space
- BUYING SIGNAL DETECTION: If client says yes/interested/book/visit/confirm/kati/garnu/hajur in a positive context, end your reply with the exact tag: [HOT_LEAD]
- ESCALATE: If complex custom deal or aggressive negotiation, end reply with: [ESCALATE]`;

return [{
  json: {
    ...msg,
    leadName,
    spaceName,
    priceLabel,
    currentStatus,
    rowNumber,
    systemPrompt,
    userMessage: msg.text
  }
}];

const geminiResp = $input.first().json;
const ctx = $('Build AI Context').first().json;

// Extract text from Gemini response
let replyText = '';
try {
  replyText = geminiResp.candidates[0].content.parts[0].text || '';
} catch(e) {
  replyText = 'Namaste! Thank you for your interest. Our team will contact you shortly. 🙏';
}

// Detect signals
const isHotLead = replyText.includes('[HOT_LEAD]');
const isEscalate = replyText.includes('[ESCALATE]');

// Clean tags from reply before sending to client
const cleanReply = replyText
  .replace('[HOT_LEAD]', '')
  .replace('[ESCALATE]', '')
  .trim();

return [{
  json: {
    ...ctx,
    replyText: cleanReply,
    isHotLead,
    isEscalate,
    needsUpdate: isHotLead || isEscalate
  }
}];

